entries.source:
// Get the size of an array
// inputs: []  returns: 3n
East.function([], IntegerType, ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.size();
    })

// Get an element by index
// inputs: []  returns: 20n
East.function([], IntegerType, ($) => {
        const a = $.const([10n, 20n, 30n], ArrayType(IntegerType));
        return a.get(1n);
    })

// Get an element by index with a default for out-of-bounds
// inputs: []  returns: 40n
East.function([], IntegerType, ($) => {
        const a = $.const([10n, 20n, 30n], ArrayType(IntegerType));
        return a.get(3n, _ => 40n);
    })

// Safely get an element by index, returning an option
// inputs: []  returns: some(30n)
East.function([], undefined, ($) => {
        const a = $.const([10n, 20n, 30n], ArrayType(IntegerType));
        return a.tryGet(2n);
    })

// Check if an index is within bounds
// inputs: []  returns: true
East.function([], BooleanType, ($) => {
        const a = $.const([10n, 20n, 30n], ArrayType(IntegerType));
        return a.has(1n);
    })

// Push items to the end of an array
// inputs: []  returns: [1n, 2n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.let([], ArrayType(IntegerType));
        $(a.pushLast(1n));
        $(a.pushLast(2n));
        return a;
    })

// Push an item to the front of an array
// inputs: []  returns: [0n, 1n, 2n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.let([1n, 2n], ArrayType(IntegerType));
        $(a.pushFirst(0n));
        return a;
    })

// Remove and return the last element
// inputs: []  returns: 3n
East.function([], IntegerType, ($) => {
        const a = $.let([1n, 2n, 3n], ArrayType(IntegerType));
        return a.popLast();
    })

// Remove and return the first element
// inputs: []  returns: 1n
East.function([], IntegerType, ($) => {
        const a = $.let([1n, 2n, 3n], ArrayType(IntegerType));
        return a.popFirst();
    })

// Merge a value at an index using a combine function
// inputs: []  returns: [11n, 2n, 3n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.let([1n, 2n, 3n], ArrayType(IntegerType));
        $(a.merge(0n, East.value(10n), ($, existing, newValue) => existing.add(newValue)));
        return a;
    })

// Merge all elements pairwise with another array
// inputs: []  returns: [11n, 12n, 13n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.let([1n, 2n, 3n], ArrayType(IntegerType));
        $(a.mergeAll(East.value([10n, 10n, 10n]), ($, existing, newValue) => existing.add(newValue)));
        return a;
    })

// Append another array to the end (mutating)
// inputs: []  returns: [1n, 2n, 3n, 4n, 5n, 6n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.let([1n, 2n, 3n], ArrayType(IntegerType));
        $(a.append([4n, 5n, 6n]));
        return a;
    })

// Prepend another array to the front (mutating)
// inputs: []  returns: [4n, 5n, 6n, 1n, 2n, 3n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.let([1n, 2n, 3n], ArrayType(IntegerType));
        $(a.prepend([4n, 5n, 6n]));
        return a;
    })

// Sort an array (returns new sorted array)
// inputs: []  returns: [1n, 2n, 3n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([2n, 3n, 1n], ArrayType(IntegerType));
        return a.sort();
    })

// Sort an array by a projected key (descending via negate)
// inputs: []  returns: [3n, 2n, 1n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([2n, 3n, 1n], ArrayType(IntegerType));
        return a.sort(($, x) => x.negate());
    })

// Sort an array in place (mutating)
// inputs: []  returns: [1n, 2n, 3n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.let([3n, 1n, 2n], ArrayType(IntegerType));
        $(a.sortInPlace());
        return a;
    })

// Reverse the order of elements (returns new array)
// inputs: []  returns: [3n, 2n, 1n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.reverse();
    })

// Reverse an array in place (mutating)
// inputs: []  returns: [3n, 2n, 1n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.let([1n, 2n, 3n], ArrayType(IntegerType));
        $(a.reverseInPlace());
        return a;
    })

// Check if an array is sorted
// inputs: []  returns: true
East.function([], BooleanType, ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.isSorted();
    })

// Generate an array of N elements using a builder function
// inputs: []  returns: [1n, 2n, 3n, 4n, 5n, 6n]
East.function([], ArrayType(IntegerType), ($) => {
        return East.Array.generate(6n, IntegerType, ($, i) => i.add(1n));
    })

// Create an array with a range of integers
// inputs: []  returns: [0n, 1n, 2n, 3n, 4n, 5n]
East.function([], ArrayType(IntegerType), ($) => {
        return East.Array.range(0n, 6n);
    })

// Create an array with a range of integers with a step
// inputs: []  returns: [0n, 2n, 4n]
East.function([], ArrayType(IntegerType), ($) => {
        return East.Array.range(0n, 6n, 2n);
    })

// Create equally-spaced float values between start and stop
// inputs: []  returns: [0.0, 0.25, 0.5, 0.75, 1.0]
East.function([], ArrayType(FloatType), ($) => {
        return East.Array.linspace(0.0, 1.0, 5n);
    })

// Transform each element with map
// inputs: []  returns: [20n, 40n, 60n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([10n, 20n, 30n], ArrayType(IntegerType));
        return a.map(($, x) => x.multiply(2n));
    })

// Transform each element with map using the index
// inputs: []  returns: [0n, 20n, 60n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([10n, 20n, 30n], ArrayType(IntegerType));
        return a.map(($, x, i) => x.multiply(i));
    })

// Filter elements matching a condition
// inputs: []  returns: [20n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([10n, 20n, 30n], ArrayType(IntegerType));
        return a.filter(($, x) => East.equal(x.remainder(20n), 0n));
    })

// Filter and transform in one step using option return
// inputs: []  returns: ["1", "3", "5"]
East.function([], ArrayType(StringType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.filterMap(($, x) => East.equal(x.remainder(2n), 1n).ifElse(() => some(Expr.print(x)), () => none));
    })

// Map each element to an array and flatten the result
// inputs: []  returns: [1n, 11n, 2n, 12n, 3n, 13n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.flatMap((_$, x) => [x, x.add(10n)]);
    })

// Flatten a nested array of arrays
// inputs: []  returns: [1n, 2n, 3n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([[1n, 2n], [3n]], ArrayType(ArrayType(IntegerType)));
        return a.flatMap();
    })

// Iterate over array elements with forEach
// inputs: []  returns: ["a", "b", "c"]
East.function([], ArrayType(StringType), ($) => {
        const from = $.const(["a", "b", "c"], ArrayType(StringType));
        const log = $.let([], ArrayType(StringType));
        $(from.forEach(($, x) => log.pushLast(x)));
        return log;
    })

// Find the index of the first occurrence of a value
// inputs: []  returns: some(1n)
East.function([], undefined, ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.findFirst(2n);
    })

// Find the first element matching a projected value
// inputs: []  returns: some(1n)
East.function([], undefined, ($) => {
        const a = $.const([10n, 20n, 30n], ArrayType(IntegerType));
        return a.findFirst(4n, ($, x) => x.divide(5n));
    })

// Find the indices of all occurrences of a value
// inputs: []  returns: [0n, 2n, 4n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([5n, 10n, 5n, 20n, 5n], ArrayType(IntegerType));
        return a.findAll(5n);
    })

// Find first element that maps to some, returning the mapped value
// inputs: []  returns: some(50n)
East.function([], undefined, ($) => {
        const a = $.const([2n, 4n, 5n, 7n, 9n], ArrayType(IntegerType));
        return a.firstMap(($, x) => East.equal(x.remainder(2n), 1n).ifElse(() => some(x.multiply(10n)), () => none));
    })

// Binary search for the first position of a value in a sorted array
// inputs: []  returns: 1n
East.function([], IntegerType, ($) => {
        const a = $.const([1n, 3n, 3n, 3n, 4n], ArrayType(IntegerType));
        return a.findSortedFirst(3n);
    })

// Binary search for the range of a value in a sorted array
// inputs: []  returns: { start: 1n, end: 4n }
East.function([], undefined, ($) => {
        const a = $.const([1n, 3n, 3n, 3n, 4n], ArrayType(IntegerType));
        return a.findSortedRange(3n);
    })

// Reduce an array to a single value with an initial accumulator
// inputs: []  returns: 16n
East.function([], IntegerType, ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.reduce(($, acc, x) => acc.add(x), 10n);
    })

// Map then reduce without an initial value
// inputs: []  returns: 12n
East.function([], IntegerType, ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.mapReduce((_$, x, _i) => x.multiply(2n), ($, acc, x) => acc.add(x));
    })

// Sum all elements in an array
// inputs: []  returns: 6n
East.function([], IntegerType, ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.sum();
    })

// Sum projected values
// inputs: []  returns: 9n
East.function([], IntegerType, ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.sum(($, x) => x.add(1n));
    })

// Compute the mean of array elements
// inputs: []  returns: 2.0
East.function([], FloatType, ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.mean();
    })

// Find the maximum element
// inputs: []  returns: 3n
East.function([], IntegerType, ($) => {
        const a = $.const([3n, 1n, 2n], ArrayType(IntegerType));
        return a.maximum();
    })

// Find the minimum element
// inputs: []  returns: 1n
East.function([], IntegerType, ($) => {
        const a = $.const([3n, 1n, 2n], ArrayType(IntegerType));
        return a.minimum();
    })

// Find the index of the maximum element
// inputs: []  returns: some(1n)
East.function([], undefined, ($) => {
        const a = $.const([1n, 3n, 2n], ArrayType(IntegerType));
        return a.findMaximum();
    })

// Find the index of the minimum element
// inputs: []  returns: some(1n)
East.function([], undefined, ($) => {
        const a = $.const([3n, 1n, 2n], ArrayType(IntegerType));
        return a.findMinimum();
    })

// Check if all elements satisfy a condition (boolean array)
// inputs: []  returns: true
East.function([], BooleanType, ($) => {
        const a = $.const([true, true], ArrayType(BooleanType));
        return a.every();
    })

// Check if any element satisfies a condition (boolean array)
// inputs: []  returns: true
East.function([], BooleanType, ($) => {
        const a = $.const([true, false], ArrayType(BooleanType));
        return a.some();
    })

// Extract a slice of an array
// inputs: []  returns: [1n, 2n, 3n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.slice(0n, 3n);
    })

// Get elements at specific indices
// inputs: []  returns: [1n, 3n, 5n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.getKeys([0n, 2n, 4n]);
    })

// Concatenate two arrays (returns new array)
// inputs: []  returns: [1n, 2n, 3n, 4n, 5n, 6n]
East.function([], ArrayType(IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n], ArrayType(IntegerType));
        return a.concat([5n, 6n]);
    })

// Convert an array to a set (removes duplicates)
// inputs: []  returns: new Set([1n, 2n, 3n])
East.function([], SetType(IntegerType), ($) => {
        const a = $.const([1n, 2n, 2n, 3n, 3n, 3n], ArrayType(IntegerType));
        return a.toSet();
    })

// Convert to set with a projection function
// inputs: []  returns: new Set([-1n, -2n, -3n])
East.function([], SetType(IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.toSet(($, x) => x.negate());
    })

// Convert an array to a dict keyed by index
// inputs: []  returns: new Map([[0n, 1n], [1n, 2n], [2n, 3n]])
East.function([], DictType(IntegerType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.toDict();
    })

// Convert to dict with a custom key function
// inputs: []  returns: new Map([["0", 1n], ["1", 2n], ["2", 3n]])
East.function([], DictType(StringType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.toDict((_$, _x, i) => East.print(i));
    })

// Convert to dict with conflict resolution (group-map-reduce pattern)
// inputs: []  returns: new Map([[0n, 12n], [1n, 9n]])
East.function([], DictType(IntegerType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.toDict((_$, x) => x.remainder(2n), (_$, x) => x, (_$, a, b, _k) => a.add(b));
    })

// Join string array elements with a separator
// inputs: []  returns: "a, b, c"
East.function([], StringType, ($) => {
        const a = $.const(["a", "b", "c"], ArrayType(StringType));
        return a.stringJoin(", ");
    })

// Join string array elements with a separator
// inputs: []  returns: "a, b, c"
East.function([], StringType, ($) => {
        const a = $.const([{ key: "a" }, { key: "b" }, { key: "c" }], ArrayType(StructType({ key: StringType })));
        return a.map(($, x) => x.key).stringJoin(", ");
    })

// Map elements to sets and flatten into one set
// inputs: []  returns: new Set([1n, 2n, 3n, 11n, 12n, 13n])
East.function([], SetType(IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.flattenToSet((_$, x) => new Set([x, x.add(10n)]));
    })

// Map elements to dicts and flatten into one dict
// inputs: []  returns: new Map([["1", 1n], ["2", 2n], ["3", 3n], ["11", 11n], ["12", 12n], ["13", 13n]])
East.function([], DictType(StringType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.flattenToDict((_$, x) => new Map([[East.print(x), x], [East.print(x.add(10n)), x.add(10n)]]));
    })

// Count occurrences of each element
// inputs: []  returns: new Map([[1n, 2n], [2n, 2n], [3n, 1n]])
East.function([], DictType(IntegerType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n, 1n, 2n], ArrayType(IntegerType));
        return a.groupSize();
    })

// Count elements grouped by a key function (even/odd)
// inputs: []  returns: new Map([[0n, 2n], [1n, 3n]])
East.function([], DictType(IntegerType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n, 1n, 2n], ArrayType(IntegerType));
        return a.groupSize((_$, x) => x.remainder(2n));
    })

// Group elements and reduce each group with an init function
// inputs: []  returns: new Map([[0n, 12n], [1n, 14n]])
East.function([], DictType(IntegerType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.groupReduce((_$, x, _i) => x.remainder(2n), (_$, _k) => 10n, (_$, acc, x, _i) => acc.add(x));
    })

// Sum elements grouped by a key function
// inputs: []  returns: new Map([[0n, 12n], [1n, 9n]])
East.function([], DictType(IntegerType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.groupSum((_$, x) => x.remainder(2n));
    })

// Compute mean for each group
// inputs: []  returns: new Map([[0n, 4.0], [1n, 3.0]])
East.function([], DictType(IntegerType, FloatType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.groupMean((_$, x) => x.remainder(2n));
    })

// Check if all elements in each group satisfy a predicate
// inputs: []  returns: new Map([[0n, true], [1n, true]])
East.function([], DictType(IntegerType, BooleanType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.groupEvery((_$, x) => x.remainder(2n), (_$, x) => East.greater(x, 0n));
    })

// Check if any element in each group satisfies a predicate
// inputs: []  returns: new Map([[0n, true], [1n, true]])
East.function([], DictType(IntegerType, BooleanType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.groupSome((_$, x) => x.remainder(2n), (_$, x) => East.greater(x, 4n));
    })

// Collect elements into arrays grouped by a key
// inputs: []  returns: new Map([[0n, [2n, 4n, 6n]], [1n, [1n, 3n, 5n]]])
East.function([], DictType(IntegerType, ArrayType(IntegerType)), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.groupToArrays((_$, x) => x.remainder(2n));
    })

// Collect elements into sets grouped by a key (deduplicates)
// inputs: []  returns: new Map([[0n, new Set([2n])], [1n, new Set([1n, 3n])]])
East.function([], DictType(IntegerType, SetType(IntegerType)), ($) => {
        const a = $.const([1n, 2n, 3n, 1n, 2n, 3n], ArrayType(IntegerType));
        return a.groupToSets((_$, x) => x.remainder(2n));
    })

// Find the minimum element in each group
// inputs: []  returns: new Map([[0n, 2n], [1n, 1n]])
East.function([], DictType(IntegerType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.groupMinimum((_$, x) => x.remainder(2n));
    })

// Find the maximum element in each group
// inputs: []  returns: new Map([[0n, 6n], [1n, 5n]])
East.function([], DictType(IntegerType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.groupMaximum((_$, x) => x.remainder(2n));
    })

// Find first occurrence of a value within each group
// inputs: []  returns: new Map<bigint
East.function([], undefined, ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.groupFindFirst((_$, x) => x.remainder(2n), 4n);
    })

// Find all occurrences of a value within each group
// inputs: []  returns: new Map([[0n, [1n, 3n, 5n]], [1n, []]])
East.function([], undefined, ($) => {
        const a = $.const([1n, 2n, 3n, 2n, 5n, 2n], ArrayType(IntegerType));
        return a.groupFindAll((_$, x) => x.remainder(2n), 2n);
    })

// Find index of minimum element within each group
// inputs: []  returns: new Map([[0n, 1n], [1n, 0n]])
East.function([], DictType(IntegerType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.groupFindMinimum((_$, x) => x.remainder(2n));
    })

// Find index of maximum element within each group
// inputs: []  returns: new Map([[0n, 5n], [1n, 4n]])
East.function([], DictType(IntegerType, IntegerType), ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.groupFindMaximum((_$, x) => x.remainder(2n));
    })

// Group into nested dicts (outer key + inner key)
// inputs: []  returns: new Map([
        [0n, new Map([[2n, 2n], [4n, 4n], [6n, 6n]])],
        [1n, new Map([[1n, 1n], [3n, 3n], [5n, 5n]])],
    ])
East.function([], undefined, ($) => {
        const a = $.const([1n, 2n, 3n, 4n, 5n, 6n], ArrayType(IntegerType));
        return a.groupToDicts((_$, x) => x.remainder(2n), (_$, x) => x);
    })

// Encode an array of structs as CSV
// inputs: []  returns: "name,age\r\nAlice,30\r\nBob,25"
East.function([], StringType, ($) => {
        const T = StructType({ name: StringType, age: IntegerType });
        const arr = $.const([
            { name: "Alice", age: 30n },
            { name: "Bob", age: 25n },
        ], ArrayType(T));
        const result = $.let(arr.encodeCsv());
        return result.decodeUtf8();
    })

// Check if two arrays are equal
// inputs: []  returns: true
East.function([], BooleanType, ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.equals([1n, 2n, 3n]);
    })

// Check if two arrays are not equal
// inputs: []  returns: true
East.function([], BooleanType, ($) => {
        const a = $.const([1n, 2n, 3n], ArrayType(IntegerType));
        return a.notEquals([1n, 2n]);
    })

// Get the size of a blob in bytes
// inputs: []  returns: 3n
East.function([], IntegerType, ($) => {
        const b = $.const(Uint8Array.from([1, 2, 3]), BlobType);
        return b.size();
    })

// Get a byte value from a blob by index
// inputs: []  returns: 20n
East.function([], IntegerType, ($) => {
        const b = $.const(Uint8Array.from([10, 20, 30]), BlobType);
        return b.getUint8(1n);
    })

// Encode a string to a UTF-8 blob
// inputs: []  returns: Uint8Array.from([0x48, 0x65, 0x6c, 0x6c, 0x6f])
East.function([], BlobType, ($) => {
        const s = $.const("Hello", StringType);
        return s.encodeUtf8();
    })

// Decode a UTF-8 blob to a string
// inputs: []  returns: "Hello"
East.function([], StringType, ($) => {
        const b = $.const(Uint8Array.from([0x48, 0x65, 0x6c, 0x6c, 0x6f]), BlobType);
        return b.decodeUtf8();
    })

